import React, { useEffect, useMemo, useState } from 'react'
import { taskService } from '../../services/api'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
]

const normalize = (v) => String(v || '').toUpperCase()

const formatDateTime = (value) => {
  if (!value) return '-'
  const d = new Date(value)
  if (Number.isNaN(d.getTime())) return value
  return d.toLocaleString('vi-VN')
}

const getStatusLabel = (status) => {
  switch (normalize(status)) {
    case 'PENDING': return 'Chờ xử lý'
    case 'IN_PROGRESS': return 'Đang thực hiện'
    case 'COMPLETED': return 'Hoàn thành'
    default: return status || '-'
  }
}

const getStatusClass = (status) => {
  switch (normalize(status)) {
    case 'PENDING': return 'task-status task-status--pending'
    case 'IN_PROGRESS': return 'task-status task-status--progress'
    case 'COMPLETED': return 'task-status task-status--done'
    default: return 'task-status'
  }
}

const TechnicianTasks = () => {
  const { user } = useAuth()

  const [tasks, setTasks] = useState([])
  const [loading, setLoading] = useState(true)

  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')

  const [pageSize, setPageSize] = useState(10)
  const [currentPage, setCurrentPage] = useState(1)

  const [selectedTask, setSelectedTask] = useState(null)

  // CREATE TASK MODAL
  const [isCreateOpen, setIsCreateOpen] = useState(false)
  const [form, setForm] = useState({
    task_title: '',
    task_type: '',
    pond_id: '',
    description: '',
    due_date: '',
    assigned_to: ''
  })

  const getFilteredPonds = (taskType) => {
  if (!taskType) return ponds

  switch (taskType) {
    case 'FEEDING':
    case 'TREATMENT':
      return ponds.filter(p => p.status === 'DANG_NUOI')

    case 'POND_PROCESS':
      return ponds.filter(p => p.status === 'DANG_CAI_TAO')

    case 'HARVEST':
      return ponds.filter(p => p.status === 'DANG_NUOI')

    default:
      return ponds
  }
}

  useEffect(() => {
    fetchTasks()
  }, [])

  const fetchTasks = async () => {
    try {
      setLoading(true)
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách công việc', type: 'error' })
    } finally {
      setLoading(false)
    }
  }

  const filtered = useMemo(() => {
    const s = search.trim().toLowerCase()

    return tasks.filter(t => {
      const matchSearch =
        !s ||
        t.task_title?.toLowerCase().includes(s) ||
        t.pond_name?.toLowerCase().includes(s)

      const matchStatus =
        statusFilter === 'ALL' || normalize(t.status) === statusFilter

      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize))
  const safePage = Math.min(currentPage, totalPages)

  const paginated = filtered.slice(
    (safePage - 1) * pageSize,
    safePage * pageSize
  )

  const handleCreateTask = async () => {
    try {
      await taskService.createTask(form)

      showToast({ title: 'Tạo công việc thành công', type: 'success' })

      setIsCreateOpen(false)
      setForm({
        task_title: '',
        task_type: '',
        pond_id: '',
        description: '',
        due_date: '',
        assigned_to: ''
      })

      fetchTasks()
    } catch {
      showToast({ title: 'Không thể tạo công việc', type: 'error' })
    }
  }

  const handleStatusChange = async (taskId, status) => {
    try {
      await taskService.updateTaskStatus(taskId, status)
      showToast({ title: 'Cập nhật thành công', type: 'success' })
      fetchTasks()
    } catch {
      showToast({ title: 'Lỗi cập nhật trạng thái', type: 'error' })
    }
  }

  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard admin-page technician-tasks">

      <div className="table-container table-panel">

        {/* HEADER */}
        <div className="table-header">
          <div>
            <h2>Quản lý công việc</h2>
            <p className="table-subtitle">Phân công & theo dõi công việc</p>
          </div>

          <button
            className="btn btn-primary"
            onClick={() => setIsCreateOpen(true)}
          >
            + Phân công công việc
          </button>
        </div>

        {/* FILTER */}
        <div className="table-toolbar technician-tasks_toolbar">
          <input
            placeholder="Tìm theo tên công việc / ao..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value)
              setCurrentPage(1)
            }}
          />

          <select
            value={statusFilter}
            onChange={(e) => {
              setStatusFilter(e.target.value)
              setCurrentPage(1)
            }}
          >
            {STATUS_OPTIONS.map(o => (
              <option key={o.value} value={o.value}>{o.label}</option>
            ))}
          </select>
        </div>

        {/* TABLE */}
        <div className="table-wrapper">
          <table className="table-base">
            <thead>
              <tr>
                <th>Công việc</th>
                <th>Ao</th>
                <th>Người giao</th>
                <th>Người nhận</th>
                <th>Hạn</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>

            <tbody>
              {paginated.length === 0 ? (
                <tr>
                  <td colSpan="7" className="table-empty-row">
                    Không có dữ liệu
                  </td>
                </tr>
              ) : (
                paginated.map(task => (
                  <tr key={task.task_id}>
                    <td>
                      <strong>{task.task_title}</strong>
                      <div className="muted">{task.description}</div>
                    </td>

                    <td>{task.pond_name || '-'}</td>
                    <td>{task.assigned_by_name || '-'}</td>
                    <td>{task.assigned_to_name || '-'}</td>
                    <td>{formatDateTime(task.due_date)}</td>

                    <td>
                      <span className={getStatusClass(task.status)}>
                        {getStatusLabel(task.status)}
                      </span>
                    </td>

                    <td>
                      <div className="table-actions">
                        <button onClick={() => setSelectedTask(task)}>ⓘ</button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* PAGINATION */}
        <div className="table-pagination">
          <span>{filtered.length} công việc</span>

          <div>
            <button
              disabled={safePage <= 1}
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
            >
              ‹
            </button>

            <span>{safePage}</span>

            <button
              disabled={safePage >= totalPages}
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
            >
              ›
            </button>
          </div>
        </div>
      </div>

      {/* CREATE MODAL */}
      {isCreateOpen && (
  <div className="modal" onClick={() => setIsCreateOpen(false)}>
    <div className="modal-content" onClick={(e) => e.stopPropagation()}>

      <h3>Phân công công việc</h3>

      {/* LOẠI CÔNG VIỆC */}
      <select
        value={form.task_type}
        onChange={(e) =>
          setForm({ ...form, task_type: e.target.value, pond_id: '', product_id: '' })
        }
      >
        <option value="">-- Loại công việc --</option>
        <option value="FEEDING">Cho ăn</option>
        <option value="TREATMENT">Cho thuốc</option>
        <option value="HARVEST">Thu hoạch</option>
        <option value="POND_PROCESS">Xử lý ao</option>
        <option value="ENV_CHECK">Kiểm tra môi trường</option>
      </select>

      {/* AO (FILTER THEO LOẠI CÔNG VIỆC) */}
      <select
        value={form.pond_id}
        onChange={(e) => setForm({ ...form, pond_id: e.target.value })}
      >
        <option value="">-- Chọn ao --</option>

        {getFilteredPonds(form.task_type).map(p => (
          <option key={p.pond_id} value={p.pond_id}>
            {p.pond_name}
          </option>
        ))}
      </select>

      {/* MÔ TẢ */}
      <textarea
        placeholder="Mô tả công việc (không bắt buộc)"
        value={form.description}
        onChange={(e) =>
          setForm({ ...form, description: e.target.value })
        }
      />

      {/* SẢN PHẨM (HIỆN THEO LOẠI TASK) */}
      {(form.task_type === 'FEEDING' || form.task_type === 'TREATMENT' || form.task_type === 'POND_PROCESS') && (
        <>
          <select
            value={form.product_id}
            onChange={(e) =>
              setForm({ ...form, product_id: e.target.value })
            }
          >
            <option value="">-- Chọn sản phẩm --</option>

            {getFilteredProducts(form.task_type).map(p => (
              <option key={p.product_id} value={p.product_id}>
                {p.product_name}
              </option>
            ))}
          </select>

          <input
            type="number"
            placeholder="Số lượng sử dụng"
            value={form.quantity || ''}
            onChange={(e) =>
              setForm({ ...form, quantity: e.target.value })
            }
          />
        </>
      )}

      {/* HẠN CHÓT */}
      <input
        type="datetime-local"
        value={form.due_date}
        onChange={(e) =>
          setForm({ ...form, due_date: e.target.value })
        }
      />

      {/* WORKER GRID */}
      <div className="worker-grid">
        {workers.map(w => (
          <label key={w.user_id} className="worker-item">
            <input
              type="checkbox"
              checked={form.assigned_workers?.includes(w.user_id)}
              onChange={() => toggleWorker(w.user_id)}
            />
            {w.full_name}
          </label>
        ))}
      </div>

      {/* ACTION */}
      <div className="modal-actions">
        <button onClick={() => setIsCreateOpen(false)}>
          Hủy
        </button>

        <button onClick={handleCreateTask}>
          Phân công
        </button>
      </div>

    </div>
  </div>
)}

      {/* DETAIL MODAL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>

            <h3>Chi tiết công việc</h3>

            <p><b>Tiêu đề:</b> {selectedTask.task_title}</p>
            <p><b>Mô tả:</b> {selectedTask.description}</p>
            <p><b>Ao:</b> {selectedTask.pond_name}</p>

            <select
              value={selectedTask.status}
              onChange={(e) =>
                handleStatusChange(selectedTask.task_id, e.target.value)
              }
            >
              <option value="PENDING">Chờ xử lý</option>
              <option value="IN_PROGRESS">Đang thực hiện</option>
              <option value="COMPLETED">Hoàn thành</option>
            </select>

            <button onClick={() => setSelectedTask(null)}>
              Đóng
            </button>

          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
